const fs = require('node:fs');
const path = require('node:path');

const root = path.resolve(__dirname, '..');
const schemaPath = path.join(root, 'docs', 'supabase', 'schema.sql');
const migrationsDir = path.join(root, 'supabase', 'migrations');
const migrationPath = path.join(migrationsDir, '20260606000000_project_odysseus_schema.sql');

const schema = fs.readFileSync(schemaPath, 'utf8');

// The Supabase CLI requires files under supabase/migrations, but the project
// keeps docs/supabase/schema.sql as the editable schema source of truth.
const generated = [
  '-- Generated by scripts/sync-supabase-migration.cjs.',
  '-- Edit docs/supabase/schema.sql, then run npm run supabase:migration:sync.',
  '',
  schema.trim(),
  '',
].join('\n');

fs.mkdirSync(migrationsDir, { recursive: true });
fs.writeFileSync(migrationPath, generated, 'utf8');
console.log(`Synced ${path.relative(root, schemaPath)} -> ${path.relative(root, migrationPath)}`);
